PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "role" varchar not null default 'staff', "remember_token" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "bookings" ("id" integer primary key autoincrement not null, "booking_reference" varchar not null, "guest_id" integer not null, "user_id" integer, "status" varchar not null default 'pending', "booking_type" varchar not null default 'stay', "adults_count" integer not null default '1', "children_count" integer not null default '0', "checked_in_at" datetime not null, "checked_out_at" datetime, "actual_checked_in_at" datetime, "actual_checked_out_at" datetime, "total_price" numeric not null, "discount_amount" numeric not null default '0', "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("guest_id") references "guests"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "room_types" ("id" integer primary key autoincrement not null, "name" varchar not null, "category" varchar not null default 'stay', "description" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "amenities" ("id" integer primary key autoincrement not null, "name" varchar not null, "description" text, "is_standalone" tinyint(1) not null default '0', "price" numeric not null default '0', "icon" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "payments" ("id" integer primary key autoincrement not null, "booking_id" integer not null, "amount" numeric not null, "payment_type" varchar not null default 'room_charge', "type" varchar not null, "payment_method" varchar not null, "status" varchar not null default 'completed', "paid_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("booking_id") references "bookings"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "guests" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar, "phone" varchar not null, "address" text, "id_card_number" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "rooms" ("id" integer primary key autoincrement not null, "room_type_id" integer not null, "room_number" varchar not null, "floor" integer not null default '1', "status" varchar not null default 'available', "is_occupied" tinyint(1) not null default '0', "pictures" text, "videos" text, "price_per_night" numeric not null, "created_at" datetime, "updated_at" datetime, foreign key("room_type_id") references "room_types"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "booking_room" ("id" integer primary key autoincrement not null, "booking_id" integer not null, "room_id" integer not null, "price_at_booking" numeric, "created_at" datetime, "updated_at" datetime, foreign key("booking_id") references "bookings"("id") on delete cascade, foreign key("room_id") references "rooms"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "amenity_room" ("id" integer primary key autoincrement not null, "amenity_id" integer not null, "room_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("amenity_id") references "amenities"("id") on delete cascade, foreign key("room_id") references "rooms"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "guest_orders" ("id" integer primary key autoincrement not null, "booking_id" integer not null, "payment_id" integer, "total_amount" numeric not null default '0', "status" varchar not null default 'pending', "created_at" datetime, "updated_at" datetime, foreign key("booking_id") references "bookings"("id") on delete cascade, foreign key("payment_id") references "payments"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "guest_order_items" ("id" integer primary key autoincrement not null, "guest_order_id" integer not null, "item_name" varchar not null, "category" varchar, "quantity" integer not null default '1', "unit_price" numeric not null, "total_price" numeric not null, "created_at" datetime, "updated_at" datetime, foreign key("guest_order_id") references "guest_orders"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "galleries" ("id" integer primary key autoincrement not null, "title" varchar not null, "type" varchar check ("type" in ('image', 'video')) not null default 'image', "url" varchar not null, "thumbnail" varchar, "room_type_id" integer, "description" text, "is_active" tinyint(1) not null default '1', "sort_order" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("room_type_id") references "room_types"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "team_members" ("id" integer primary key autoincrement not null, "name" varchar not null, "role" varchar not null, "department" varchar not null, "bio" text, "image" varchar, "sort_order" integer not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "amenity_bookings" ("id" integer primary key autoincrement not null, "booking_id" integer not null, "amenity_id" integer not null, "price_at_booking" numeric not null, "quantity" integer not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("booking_id") references "bookings"("id"), foreign key("amenity_id") references "amenities"("id"));
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE INDEX "personal_access_tokens_tokenable_type_tokenable_id_index" on "personal_access_tokens" ("tokenable_type", "tokenable_id");
CREATE UNIQUE INDEX "personal_access_tokens_token_unique" on "personal_access_tokens" ("token");
CREATE INDEX "personal_access_tokens_expires_at_index" on "personal_access_tokens" ("expires_at");
CREATE UNIQUE INDEX "bookings_booking_reference_unique" on "bookings" ("booking_reference");
CREATE UNIQUE INDEX "guests_email_unique" on "guests" ("email");
CREATE UNIQUE INDEX "rooms_room_number_unique" on "rooms" ("room_number");
COMMIT;
